file.content:
{
	"$schema": "https://schemas.wp.org/trunk/block.json",
	"apiVersion": 3,
	"name": "telex/addtoany-block",
	"version": "0.1.0",
	"title": "AddToAny Widget",
	"category": "widgets",
	"icon": "share",
	"description": "AddToAnyの共有ボタンを表示します",
	"keywords": ["addtoany", "share", "social", "widget"],
	"example": {},
	"attributes": {
		"buttonSize": {
			"type": "number",
			"default": 32
		},
		"buttonStyle": {
			"type": "string",
			"default": "default",
			"enum": ["default", "floating", "none"]
		}
	},
	"supports": {
		"html": false,
		"align": ["left", "center", "right", "wide", "full"]
	},
	"textdomain": "telex-addtoany-block",
	"editorScript": "file:./index.js",
	"editorStyle": "file:./index.css",
	"style": "file:./style-index.css",
	"render": "file:./render.php"
}

/**
 * Registers a new block provided a unique name and an object defining its behavior.
 *
 * @see https://developer.wordpress.org/block-editor/reference-guides/block-api/block-registration/
 */
import { registerBlockType } from '@wordpress/blocks';

/**
 * Lets webpack process CSS, SASS or SCSS files referenced in JavaScript files.
 * All files containing `style` keyword are bundled together. The code used
 * gets applied both to the front of your site and to the editor.
 *
 * @see https://www.npmjs.com/package/@wordpress/scripts#using-css
 */
import './style.scss';

/**
 * Internal dependencies
 */
import Edit from './edit';
import metadata from './block.json';

/**
 * Every block starts by registering a new block type definition.
 *
 * @see https://developer.wordpress.org/block-editor/reference-guides/block-api/block-registration/
 */
registerBlockType( metadata.name, {
	/**
	 * @see ./edit.js
	 */
	edit: Edit,
} );

/**
 * Retrieves the translation of text.
 *
 * @see https://developer.wordpress.org/block-editor/reference-guides/packages/packages-i18n/
 */
import { __ } from '@wordpress/i18n';

/**
 * React hook that is used to mark the block wrapper element.
 * It provides all the necessary props like the class name.
 *
 * @see https://developer.wordpress.org/block-editor/reference-guides/packages/packages-block-editor/#useblockprops
 */
import { useBlockProps, InspectorControls } from '@wordpress/block-editor';
import { PanelBody, RangeControl, SelectControl, Placeholder } from '@wordpress/components';
import { useState, useEffect } from '@wordpress/element';
import { share } from '@wordpress/icons';

/**
 * Lets webpack process CSS, SASS or SCSS files referenced in JavaScript files.
 * Those files can contain any CSS code that gets applied to the editor.
 *
 * @see https://www.npmjs.com/package/@wordpress/scripts#using-css
 */
import './editor.scss';

/**
 * The edit function describes the structure of your block in the context of the
 * editor. This represents what the editor will render when the block is used.
 *
 * @see https://developer.wordpress.org/block-editor/reference-guides/block-api/block-edit-save/#edit
 *
 * @param {Object}   props               Properties passed to the function.
 * @param {Object}   props.attributes    Available block attributes.
 * @param {Function} props.setAttributes Function that updates individual attributes.
 *
 * @return {Element} Element to render.
 */
export default function Edit( { attributes, setAttributes } ) {
	const { buttonSize, buttonStyle } = attributes;
	const [ isAddToAnyActive, setIsAddToAnyActive ] = useState( true );
	const blockProps = useBlockProps();

	useEffect( () => {
		// Check if AddToAny is available in the window object
		if ( typeof window.a2a !== 'undefined' || typeof window.a2a_config !== 'undefined' ) {
			setIsAddToAnyActive( true );
		}
	}, [] );

	const buttonStyleOptions = [
		{ label: __( 'デフォルト', 'telex-addtoany-block' ), value: 'default' },
		{ label: __( 'フローティング', 'telex-addtoany-block' ), value: 'floating' },
		{ label: __( 'スタイルなし', 'telex-addtoany-block' ), value: 'none' },
	];

	return (
		<>
			<InspectorControls>
				<PanelBody title={ __( 'ボタン設定', 'telex-addtoany-block' ) }>
					<RangeControl
						label={ __( 'ボタンサイズ', 'telex-addtoany-block' ) }
						value={ buttonSize }
						onChange={ ( value ) => setAttributes( { buttonSize: value } ) }
						min={ 16 }
						max={ 64 }
						step={ 2 }
					/>
					<SelectControl
						label={ __( 'ボタンスタイル', 'telex-addtoany-block' ) }
						value={ buttonStyle }
						options={ buttonStyleOptions }
						onChange={ ( value ) => setAttributes( { buttonStyle: value } ) }
					/>
				</PanelBody>
			</InspectorControls>
			<div { ...blockProps }>
				{ ! isAddToAnyActive ? (
					<Placeholder
						icon={ share }
						label={ __( 'AddToAny Widget', 'telex-addtoany-block' ) }
						instructions={ __( 'AddToAnyプラグインがインストールされていません。このブロックを使用するには、AddToAnyプラグインを有効化してください。', 'telex-addtoany-block' ) }
					/>
				) : (
					<Placeholder
						icon={ share }
						label={ __( 'AddToAny Widget', 'telex-addtoany-block' ) }
						instructions={ __( '共有ボタンがここに表示されます', 'telex-addtoany-block' ) }
					>
						<div className="addtoany-preview">
							<div 
								className="a2a_kit a2a_kit_size_32 a2a_default_style"
								style={ { fontSize: `${buttonSize}px` } }
							>
								<a className="a2a_dd" href="#">
									<span className="dashicons dashicons-share" style={ { fontSize: `${buttonSize}px` } }></span>
								</a>
								<a className="a2a_button_facebook">
									<span className="dashicons dashicons-facebook" style={ { fontSize: `${buttonSize}px` } }></span>
								</a>
								<a className="a2a_button_twitter">
									<span className="dashicons dashicons-twitter" style={ { fontSize: `${buttonSize}px` } }></span>
								</a>
								<a className="a2a_button_email">
									<span className="dashicons dashicons-email" style={ { fontSize: `${buttonSize}px` } }></span>
								</a>
							</div>
							<p className="addtoany-preview-note">
								{ __( '※ プレビュー表示です。実際のボタンはフロントエンドで表示されます。', 'telex-addtoany-block' ) }
							</p>
						</div>
					</Placeholder>
				) }
			</div>
		</>
	);
}

/**
 * The following styles get applied both on the front of your site
 * and in the editor.
 *
 * Replace them with your own styles or remove the file completely.
 */

.wp-block-telex-addtoany-block {
	margin: 1em 0;

	.addtoany-share-buttons {
		display: flex;
		flex-wrap: wrap;
		gap: 0.5em;
		align-items: center;
	}
}

/**
 * The following styles get applied inside the editor only.
 *
 * Replace them with your own styles or remove the file completely.
 */

.wp-block-telex-addtoany-block {
	.addtoany-preview {
		text-align: center;
		padding: 20px;

		.a2a_kit {
			display: inline-flex;
			gap: 8px;
			align-items: center;
			margin-bottom: 10px;

			a {
				display: inline-flex;
				align-items: center;
				justify-content: center;
				width: auto;
				height: auto;
				text-decoration: none;
				color: #555;
				transition: color 0.2s;

				&:hover {
					color: #0073aa;
				}

				.dashicons {
					width: auto;
					height: auto;
				}
			}
		}

		.addtoany-preview-note {
			font-size: 12px;
			color: #666;
			font-style: italic;
			margin-top: 10px;
		}
	}

	.components-placeholder {
		min-height: 150px;
	}
}

/**
 * Use this file for JavaScript code that you want to run in the front-end
 * on posts/pages that contain this block.
 */

/* eslint-disable no-console */
console.log( 'AddToAny Block Widget loaded' );
/* eslint-enable no-console */
